function fmtDate(s) {
  if (!s) return { mon:"???", day:"?", wday:"Unknown", full:"Unknown" };
  const d = new Date(s + "T00:00:00");
  return { mon:MONTHS[d.getMonth()], day:d.getDate(), wday:d.toLocaleDateString("en-US",{weekday:"long"}), full:d.toLocaleDateString("en-US",{month:"long",day:"numeric",year:"numeric"}) };
}
function makeGCalLink(ev) {
  const start = (ev.date||"").replace(/-/g,"");
  if (!start) return "#";
  return `https://calendar.google.com/calendar/render?action=TEMPLATE&text=${encodeURIComponent(ev.title||"")}&dates=${start}/${start}&location=${encodeURIComponent(ev.loc||"")}&details=${encodeURIComponent((ev.desc||"") + (ev.url ? "\n\nMore info: "+ev.url : ""))}`;
}

