// ─── AI EVENT FETCHER ────────────────────────────────────────────────────────
// Server CDN caches for 12hrs — no client-side caching needed
async function fetchLiveEvents() {
  const response = await fetch("/api/events");
  if (!response.ok) throw new Error("Event fetch failed: " + response.status);
  const data = await response.json();
  if (data.log) console.log("[Events API]", data.log.join(" | "));
  const events = Array.isArray(data.events) ? data.events : [];
  console.log("[Events] Received:", events.length, "events");
  return events;
}

// ─── COMPONENTS ──────────────────────────────────────────────────────────────
function SourceBadge({ url, source }) {
  if (source === "live") return <span style={{background:"#dbeafe",color:"#002868",borderRadius:20,padding:"2px 8px",fontSize:10,fontWeight:700}}>🤖 Live</span>;
  if (source === "manual") return <span style={{background:"#dbeafe",color:"#002868",borderRadius:20,padding:"2px 8px",fontSize:10,fontWeight:700}}>✏️ Manual</span>;
  if (source === "approved") return <span style={{background:"#fee2e2",color:"#C8102E",borderRadius:20,padding:"2px 8px",fontSize:10,fontWeight:700}}>✅ Verified</span>;
  if (url?.includes("allevents")) return <span style={{background:"#dbeafe",color:"#002868",borderRadius:20,padding:"2px 8px",fontSize:10,fontWeight:700}}>📌 AllEvents</span>;
  if (url?.includes("peoriaheightschamber")) return <span style={{background:"#fee2e2",color:"var(--red)",borderRadius:20,padding:"2px 8px",fontSize:10,fontWeight:700}}>📌 Chamber</span>;
  return null;
}

function EventCard({ ev }) {
  const [open, setOpen] = useState(false);
  const col = CAT_COLOR[ev.cat] || C.navy;
  const { mon, day, wday } = fmtDate(ev.date);
  const gcal = makeGCalLink(ev);
  return (
    <div className="ev-card">
      <div style={{height:4,background:col||"var(--navy)"}} />
      <div style={{padding:"14px 18px"}}>
        <div style={{display:"flex",gap:12,alignItems:"flex-start",cursor:"pointer"}} onClick={()=>setOpen(o=>!o)}>
          <div style={{background:col,color:"#fff",borderRadius:10,padding:"6px 10px",textAlign:"center",minWidth:50,flexShrink:0}}>
            <div style={{fontSize:9,fontWeight:800,letterSpacing:1}}>{mon}</div>
            <div style={{fontSize:24,fontWeight:900,lineHeight:1}}>{day}</div>
          </div>
          <div style={{flex:1,minWidth:0}}>
            <div style={{display:"flex",alignItems:"center",gap:5,flexWrap:"wrap",marginBottom:4}}>
              <span style={{background:col+"18",color:col,borderRadius:20,padding:"2px 9px",fontSize:10,fontWeight:700}}>{ev.icon} {ev.cat}</span>
              {ev.recurring && <span style={{background:"#dbeafe",color:"#002868",borderRadius:20,padding:"2px 8px",fontSize:10,fontWeight:700}}>🔄 {ev.recurring}</span>}
              {ev.featured  && <span style={{background:"var(--red)",color:"#fff",borderRadius:20,padding:"2px 8px",fontSize:10,fontWeight:700}}>⭐</span>}
              <SourceBadge url={ev.url} source={ev.source} />
            </div>
            <h3 style={{fontSize:15,color:"var(--text)",fontWeight:800,lineHeight:1.2,marginBottom:3}}>{ev.title}</h3>
            <div style={{color:"var(--text3)",fontSize:12,lineHeight:1.8}}>
              <div>🕐 {wday} · {ev.time}</div>
              <div>📍 {ev.loc}</div>
            </div>
          </div>
          <div style={{fontSize:10,color:col,fontWeight:700,flexShrink:0}}>{open?"▲":"▼"}</div>
        </div>
        {open && (
          <div>
            <p style={{margin:"12px 0 0",color:"var(--text2)",fontSize:13,lineHeight:1.65,borderTop:"1px solid var(--border)",paddingTop:10}}>{ev.desc}</p>
            <div style={{display:"flex",gap:8,flexWrap:"wrap",marginTop:12,paddingTop:10,borderTop:"1px solid var(--border)"}}>
              {ev.url && <a href={ev.url} target="_blank" rel="noreferrer" style={{display:"inline-flex",alignItems:"center",gap:5,background:"var(--navy)",color:"#fff",borderRadius:8,padding:"7px 13px",fontSize:12,fontWeight:700}}>🌐 View Event</a>}
              {ev.facebook && <a href={ev.facebook} target="_blank" rel="noreferrer" style={{display:"inline-flex",alignItems:"center",gap:5,background:"var(--navy)",color:"#fff",borderRadius:8,padding:"7px 13px",fontSize:12,fontWeight:700}}>📘 Facebook</a>}
              {ev.tickets && ev.tickets !== ev.url && <a href={ev.tickets} target="_blank" rel="noreferrer" style={{display:"inline-flex",alignItems:"center",gap:5,background:"var(--red)",color:"#fff",borderRadius:8,padding:"7px 13px",fontSize:12,fontWeight:700}}>🎟️ Tickets</a>}
              <a href={gcal} target="_blank" rel="noreferrer" style={{display:"inline-flex",alignItems:"center",gap:5,background:"var(--navy)",color:"#fff",borderRadius:8,padding:"7px 13px",fontSize:12,fontWeight:700}}>📅 Add to Calendar</a>
            </div>
          </div>
        )}
        {!open && (
          <div style={{display:"flex",gap:8,marginTop:8,paddingTop:8,borderTop:"1px solid var(--border)",alignItems:"center"}}>
            {ev.url      && <a href={ev.url}      target="_blank" rel="noreferrer" onClick={e=>e.stopPropagation()} title="View event" style={{fontSize:15,opacity:0.6}}>🌐</a>}
            {ev.facebook && <a href={ev.facebook} target="_blank" rel="noreferrer" onClick={e=>e.stopPropagation()} title="Facebook"   style={{fontSize:15,opacity:0.6}}>📘</a>}
            {ev.tickets && ev.tickets !== ev.url && <a href={ev.tickets} target="_blank" rel="noreferrer" onClick={e=>e.stopPropagation()} title="Tickets" style={{fontSize:15,opacity:0.6}}>🎟️</a>}
            <a href={gcal} target="_blank" rel="noreferrer" onClick={e=>e.stopPropagation()} title="Add to Google Calendar" style={{fontSize:15,opacity:0.6}}>📅</a>
            <span style={{marginLeft:"auto",fontSize:11,color:"var(--text3)"}}>Tap for details</span>
          </div>
        )}
      </div>
    </div>
  );
}

// ─── EVENTS TAB ───────────────────────────────────────────────────────────────
function EventsTab({ allEvents, liveStatus, lastUpdated }) {
  const [cat,setCat]   = useState("All");
  const [q,setQ]       = useState("");
  const [view,setView] = useState("upcoming");
  const today = new Date().toISOString().slice(0,10);

  // New announcements = events happening within the next 7 days
  const in7days = new Date(Date.now()+7*24*60*60*1000).toISOString().slice(0,10);
  const newAnnouncements = allEvents
    .filter(e => e.date >= today && e.date <= in7days)
    .sort((a,b) => (a.date||"").localeCompare(b.date||""));

  let filtered = allEvents
    .filter(e=>(cat==="All"||e.cat===cat) && (!q || e.title?.toLowerCase().includes(q.toLowerCase()) || e.loc?.toLowerCase().includes(q.toLowerCase())))
    .sort((a,b)=>(a.date||"").localeCompare(b.date||""));
  if (view==="upcoming") filtered = filtered.filter(e=>e.date>=today);

  const featured = filtered.filter(e=>e.featured), rest = filtered.filter(e=>!e.featured);
  const byMonth = {};
  filtered.forEach(e=>{
    const d = new Date((e.date||"2099-01-01")+"T00:00:00");
    const key = d.toLocaleDateString("en-US",{month:"long",year:"numeric"});
    if(!byMonth[key]) byMonth[key]=[];
    byMonth[key].push(e);
  });

  const lastUpdatedStr = lastUpdated ? new Date(lastUpdated).toLocaleTimeString([], {hour:"2-digit",minute:"2-digit"}) : null;

  return (
    <div>
      {/* Live status bar — no manual refresh button, auto-refreshes daily */}
      <div className={`status-bar status-${liveStatus}`}>
        {liveStatus==="loading" && <><div className="spinner" /><span style={{fontSize:12,color:"var(--navy)",fontWeight:600}}>Checking for new events…</span></>}
        {liveStatus==="loaded"  && <><span>✅</span><span style={{fontSize:12,color:"var(--navy)",fontWeight:600}}>Live events loaded{lastUpdatedStr ? ` · ${lastUpdatedStr}` : ""}</span><span style={{fontSize:11,color:"var(--text3)",marginLeft:4}}>· Kenny's · Chamber · Civic Center · Prospect Rd</span></>}
        {liveStatus==="error"   && <><span>📅</span><span style={{fontSize:12,color:"var(--navy)",fontWeight:600}}>Showing scheduled events · Updates daily</span></>}
        {liveStatus==="cached"  && <><span>📅</span><span style={{fontSize:12,color:"var(--navy)",fontWeight:600}}>Events current{lastUpdatedStr ? ` · Last checked ${lastUpdatedStr}` : ""}</span><span style={{fontSize:11,color:"var(--text3)",marginLeft:4}}>· Auto-updates every 12 hrs</span></>}
      </div>

      {/* Filters */}
      <div className="filter-bar">
        <input value={q} onChange={e=>setQ(e.target.value)} placeholder="🔍  Search events…" className="filter-input" />
        <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
          {["All",...Object.keys(CAT_COLOR)].map(c=>(
            <button key={c} onClick={()=>setCat(c)} className="cat-chip" style={{background:cat===c?(CAT_COLOR[c]||"var(--navy)"):"var(--surface2)",color:cat===c?"#fff":"var(--text2)"}}>{c}</button>
          ))}
        </div>
        <div className="view-toggle">
          {[["upcoming","📅 Upcoming"],["all","📋 All"],["calendar","🗓️ By Month"]].map(([v,l])=>(
            <button key={v} onClick={()=>setView(v)} className={"view-btn"+(view===v?" active":"")}>{l}</button>
          ))}
        </div>
      </div>

      {/* Stats */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
        {[
          {l:"Upcoming",   v:allEvents.filter(e=>e.date>=today).length,                                              c:"var(--navy)"},
          {l:"This Month", v:allEvents.filter(e=>e.date?.slice(0,7)===new Date().toISOString().slice(0,7)).length,   c:"var(--navy)"},
          {l:"Featured",   v:allEvents.filter(e=>e.featured).length,                                                 c:"var(--red)"},
          {l:"Total",      v:allEvents.length,                                                                        c:"var(--red)"},
        ].map(s=>(
          <div key={s.l} className="stat-card" style={{borderBottomColor:s.c}}>
            <div style={{fontSize:22,fontWeight:900,color:s.c}}>{s.v}</div>
            <div style={{fontSize:10,color:"var(--text3)",fontWeight:700,textTransform:"uppercase",letterSpacing:0.5,marginTop:1}}>{s.l}</div>
          </div>
        ))}
      </div>

      {view==="calendar" && (Object.keys(byMonth).length === 0 ? (
        <div style={{textAlign:"center",padding:"60px 0",color:"var(--text3)"}}><div style={{fontSize:48}}>📅</div><p style={{fontSize:18,marginTop:12,fontWeight:600}}>No events found.</p></div>
      ) : Object.keys(byMonth).map(month=>(
        <div key={month} style={{marginBottom:24}}>
          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
            <div style={{background:"var(--navy)",color:"#fff",borderRadius:8,padding:"4px 14px",fontSize:13,fontWeight:800}}>{month}</div>
            <div style={{height:2,flex:1,background:"var(--border)"}} />
            <div style={{color:"var(--text3)",fontSize:12}}>{byMonth[month].length} event{byMonth[month].length!==1?"s":""}</div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(270px,1fr))",gap:14}}>{byMonth[month].map(e=><EventCard key={e.id} ev={e}/>)}</div>
        </div>
      )))}

      {view!=="calendar"&&<>

        {/* New Announcements — events happening this week */}
        {newAnnouncements.length>0 && !q && cat==="All" && <>
          <div style={{background:"linear-gradient(135deg,#fff7e6,#fff3d6)",border:"2px solid #f0a500",borderRadius:14,padding:"14px 18px",marginBottom:22}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
              <span style={{fontSize:18}}>🆕</span>
              <span style={{fontWeight:900,color:"#b36800",fontSize:15,letterSpacing:0.3}}>New Announcements</span>
              <span style={{background:"#f0a500",color:"#fff",borderRadius:20,padding:"1px 9px",fontSize:11,fontWeight:800,marginLeft:4}}>{newAnnouncements.length}</span>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(270px,1fr))",gap:12}}>
              {newAnnouncements.map(e=><EventCard key={e.id} ev={e}/>)}
            </div>
          </div>
        </>}

        {featured.length>0&&<>
          <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
            <span style={{background:"var(--red)",color:"#fff",borderRadius:6,padding:"3px 12px",fontSize:11,fontWeight:900,letterSpacing:1}}>FEATURED</span>
            <h2 style={{color:"var(--navy)",fontSize:18,fontWeight:800}}>Highlights</h2>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:16,marginBottom:26}}>{featured.map(e=><EventCard key={e.id} ev={e}/>)}</div>
        </>}
        {rest.length>0&&<>
          <h2 style={{color:"var(--navy)",fontSize:18,marginBottom:12,fontWeight:800}}>{view==="upcoming"?"Coming Up":"All Events"} <span style={{color:"var(--text3)",fontSize:13,fontWeight:500}}>({rest.length})</span></h2>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(270px,1fr))",gap:14}}>{rest.map(e=><EventCard key={e.id} ev={e}/>)}</div>
        </>}
        {filtered.length===0&&liveStatus!=="loading"&&<div style={{textAlign:"center",padding:"60px 0",color:"var(--text3)"}}><div style={{fontSize:48}}>📅</div><p style={{fontSize:18,marginTop:12,fontWeight:600}}>No events found.</p></div>}
      </>}
    </div>
  );
}

// ─── SUBMIT EVENT (public form for businesses) ────────────────────────────────
function SubmitTab({ onSubmit }) {
  const empty = { title:"", date:"", time:"", loc:"", desc:"", cat:"Community", icon:"🏛️", url:"", facebook:"", tickets:"", contactName:"", contactEmail:"", recurring:"" };
  const [form, setForm] = useState(empty);
  const [sent, setSent] = useState(false);
  const set = (k,v) => setForm(f=>({...f,[k]:v}));
  function submit() {
    if (!form.title || !form.date || !form.contactEmail) return;
    onSubmit({ ...form, id:"sub_"+Date.now(), source:"pending", featured:false, submittedAt:new Date().toISOString() });
    setForm(empty); setSent(true); setTimeout(()=>setSent(false),5000);
  }
  const inp = (extra={}) => ({padding:"10px 13px",borderRadius:9,border:"2px solid var(--border)",fontSize:14,width:"100%",background:"var(--surface2)",color:"var(--text)",...extra});
  const lbl = {fontSize:11,fontWeight:700,color:"var(--text3)",textTransform:"uppercase",letterSpacing:0.5,display:"block",marginBottom:4};
  return (
    <div>
      <div style={{background:`linear-gradient(135deg,${C.navy},#001540)`,borderRadius:18,padding:"28px 32px",marginBottom:24,color:"#fff"}}>
        <h2 style={{fontSize:24,fontWeight:900,marginBottom:8}}>📣 Submit Your Event</h2>
        <p style={{opacity:0.85,fontSize:14,lineHeight:1.7,maxWidth:560}}>
          Business owner or event organizer in Peoria Heights? Fill out this form to have your event reviewed and added to Heights Live. We'll review your submission and post it within 24 hours.
        </p>
      </div>

      {sent ? (
        <div style={{background:"rgba(0,40,104,0.06)",border:"2px solid var(--navy)",borderRadius:16,padding:"32px",textAlign:"center"}}>
          <div style={{fontSize:48,marginBottom:12}}>🎉</div>
          <h3 style={{color:"var(--navy)",fontSize:20,fontWeight:800,marginBottom:6}}>Submission Received!</h3>
          <p style={{color:"var(--navy)",fontSize:14}}>Thank you! Your event will be reviewed and added to Heights Live within 24 hours.</p>
        </div>
      ) : (
        <div style={{background:"var(--surface)",borderRadius:16,padding:"24px 28px",boxShadow:"var(--card-shadow)",border:"1px solid var(--border)"}}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(240px,1fr))",gap:14}}>
            <div style={{gridColumn:"1/-1"}}><label style={lbl}>Event Title *</label><input value={form.title} onChange={e=>set("title",e.target.value)} placeholder="Name of your event" style={inp()} /></div>
            <div><label style={lbl}>Date *</label><input type="date" value={form.date} onChange={e=>set("date",e.target.value)} style={inp()} /></div>
            <div><label style={lbl}>Time</label><input value={form.time} onChange={e=>set("time",e.target.value)} placeholder="e.g. 6:00 PM – 9:00 PM" style={inp()} /></div>
            <div style={{gridColumn:"1/-1"}}><label style={lbl}>Venue / Location *</label><input value={form.loc} onChange={e=>set("loc",e.target.value)} placeholder="Business name and address" style={inp()} /></div>
            <div><label style={lbl}>Category</label><select value={form.cat} onChange={e=>set("cat",e.target.value)} style={inp()}>{Object.keys(CAT_COLOR).map(c=><option key={c}>{c}</option>)}</select></div>
            <div><label style={lbl}>Recurring?</label><input value={form.recurring} onChange={e=>set("recurring",e.target.value)} placeholder="e.g. Every Friday, Annual, Monthly" style={inp()} /></div>
            <div style={{gridColumn:"1/-1"}}><label style={lbl}>Description *</label><textarea value={form.desc} onChange={e=>set("desc",e.target.value)} placeholder="Describe your event — what it is, who it's for, what to expect…" style={{...inp(),height:90,resize:"vertical"}} /></div>
            <div style={{gridColumn:"1/-1",borderTop:"2px solid var(--border)",paddingTop:14}}>
              <div style={{fontSize:13,fontWeight:800,color:"var(--navy)",marginBottom:10}}>🔗 Links (paste the direct URL where people can learn more)</div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(180px,1fr))",gap:12}}>
                <div><label style={lbl}>🌐 Event / Website URL</label><input value={form.url} onChange={e=>set("url",e.target.value)} placeholder="https://..." style={inp()} /></div>
                <div><label style={lbl}>📘 Facebook Event URL</label><input value={form.facebook} onChange={e=>set("facebook",e.target.value)} placeholder="https://facebook.com/events/..." style={inp()} /></div>
                <div><label style={lbl}>🎟️ Tickets URL</label><input value={form.tickets} onChange={e=>set("tickets",e.target.value)} placeholder="https://eventbrite.com/..." style={inp()} /></div>
              </div>
            </div>
            <div style={{gridColumn:"1/-1",borderTop:"2px solid var(--border)",paddingTop:14}}>
              <div style={{fontSize:13,fontWeight:800,color:"var(--navy)",marginBottom:10}}>📬 Your Contact Info (not published — for verification only)</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                <div><label style={lbl}>Your Name *</label><input value={form.contactName} onChange={e=>set("contactName",e.target.value)} placeholder="First and last name" style={inp()} /></div>
                <div><label style={lbl}>Email Address *</label><input type="email" value={form.contactEmail} onChange={e=>set("contactEmail",e.target.value)} placeholder="your@email.com" style={inp()} /></div>
              </div>
            </div>
          </div>
          <div style={{marginTop:20,display:"flex",gap:10,alignItems:"center"}}>
            <button onClick={submit} disabled={!form.title||!form.date||!form.contactEmail} style={{background:(!form.title||!form.date||!form.contactEmail)?"#6b7280":C.red,color:"#fff",border:"none",borderRadius:10,padding:"12px 28px",fontWeight:800,fontSize:15,cursor:(!form.title||!form.date||!form.contactEmail)?"not-allowed":"pointer"}}>
              Submit Event for Review
            </button>
            <span style={{fontSize:12,color:"var(--text3)"}}>* Required fields</span>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── ADMIN TAB ────────────────────────────────────────────────────────────────
function AdminTab({ manualEvents, setManualEvents, pendingSubs, setPendingSubs, liveEvents }) {
  const [activeSection, setActiveSection] = useState("pending");
  const empty = { title:"", date:"", time:"", loc:"", desc:"", cat:"Community", icon:"🏛️", url:"", facebook:"", tickets:"", recurring:"", featured:false };
  const [form, setForm] = useState(empty);
  const [saved, setSaved] = useState(false);
  const set = (k,v) => setForm(f=>({...f,[k]:v}));

  function saveManual() {
    if (!form.title||!form.date) return;
    const newEvents = [...manualEvents, {...form, id:"manual_"+Date.now(), source:"manual"}];
    setManualEvents(newEvents);
    saveStored("manual_events", newEvents);
    setForm(empty); setSaved(true); setTimeout(()=>setSaved(false),3000);
  }
  function removeManual(id) {
    const updated = manualEvents.filter(e=>e.id!==id);
    setManualEvents(updated); saveStored("manual_events", updated);
  }
  function toggleFeatured(id) {
    const updated = manualEvents.map(e=>e.id===id?{...e,featured:!e.featured}:e);
    setManualEvents(updated); saveStored("manual_events", updated);
  }
  function approveSub(sub) {
    const approved = {...sub, source:"approved", id:"approved_"+Date.now()};
    delete approved.contactName; delete approved.contactEmail; delete approved.submittedAt;
    const newManual = [...manualEvents, approved];
    setManualEvents(newManual); saveStored("manual_events", newManual);
    const remaining = pendingSubs.filter(s=>s.id!==sub.id);
    setPendingSubs(remaining); saveStored("pending_subs", remaining);
  }
  function rejectSub(id) {
    const remaining = pendingSubs.filter(s=>s.id!==id);
    setPendingSubs(remaining); saveStored("pending_subs", remaining);
  }

  const inp = (extra={}) => ({padding:"10px 13px",borderRadius:9,border:"2px solid var(--border)",fontSize:14,width:"100%",background:"var(--surface2)",color:"var(--text)",...extra});
  const lbl = {fontSize:11,fontWeight:700,color:"var(--text3)",textTransform:"uppercase",letterSpacing:0.5,display:"block",marginBottom:4};

  const sections = [
    ["pending", `📬 Pending (${pendingSubs.length})`],
    ["add",     "➕ Add Event"],
    ["manage",  `📋 Manage (${manualEvents.length})`],
    ["live",    `🤖 Live (${liveEvents.length})`],
  ];

  return (
    <div>
      <div style={{background:`linear-gradient(135deg,${C.navy},#001540)`,borderRadius:18,padding:"22px 28px",marginBottom:20,color:"#fff"}}>
        <h2 style={{fontSize:22,fontWeight:900,marginBottom:4}}>⚙️ Admin Panel</h2>
        <p style={{opacity:0.8,fontSize:13}}>Review business submissions, add events manually, and manage all listings.</p>
      </div>

      <div style={{display:"flex",gap:8,marginBottom:20,flexWrap:"wrap"}}>
        {sections.map(([id,label])=>(
          <button key={id} onClick={()=>setActiveSection(id)} style={{background:activeSection===id?C.navy:"var(--surface2)",color:activeSection===id?C.white:C.navy,border:"none",borderRadius:10,padding:"9px 18px",fontWeight:700,fontSize:13,cursor:"pointer"}}>
            {label}{id==="pending"&&pendingSubs.length>0&&<span style={{background:"var(--red)",color:"#fff",borderRadius:20,padding:"1px 7px",fontSize:10,fontWeight:900,marginLeft:6}}>{pendingSubs.length}</span>}
          </button>
        ))}
      </div>

      {/* PENDING SUBMISSIONS */}
      {activeSection==="pending" && (
        <div>
          {pendingSubs.length===0 ? (
            <div style={{background:"var(--surface)",borderRadius:16,padding:"40px",textAlign:"center",color:"var(--text3)",boxShadow:"0 2px 8px rgba(0,0,0,0.05)"}}>
              <div style={{fontSize:40,marginBottom:10}}>📬</div>
              <p style={{fontSize:16,fontWeight:600}}>No pending submissions</p>
              <p style={{fontSize:13,marginTop:6}}>When businesses submit events via the "Submit Event" tab, they'll appear here for review.</p>
            </div>
          ) : pendingSubs.map(sub=>(
            <div key={sub.id} style={{background:"var(--surface)",borderRadius:14,padding:"20px 24px",marginBottom:14,border:"2px solid var(--navy)",boxShadow:"var(--card-shadow)"}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:12,flexWrap:"wrap",marginBottom:10}}>
                <div>
                  <h3 style={{fontSize:17,fontWeight:800,color:"var(--text)",marginBottom:4}}>{sub.title}</h3>
                  <div style={{fontSize:12,color:"var(--text3)",lineHeight:1.8}}>
                    <div>📅 {fmtDate(sub.date).full} · {sub.time}</div>
                    <div>📍 {sub.loc}</div>
                    <div>📬 Submitted by: <strong>{sub.contactName}</strong> ({sub.contactEmail})</div>
                    {sub.url && <div>🔗 <a href={sub.url} target="_blank" rel="noreferrer" style={{color:"var(--navy)"}}>{sub.url}</a></div>}
                  </div>
                </div>
                <div style={{display:"flex",gap:8,flexShrink:0}}>
                  <button onClick={()=>approveSub(sub)} style={{background:"var(--navy)",color:"#fff",border:"none",borderRadius:9,padding:"9px 18px",fontWeight:700,fontSize:13,cursor:"pointer"}}>✅ Approve</button>
                  <button onClick={()=>rejectSub(sub.id)} style={{background:"#fee2e2",color:"var(--red)",border:"none",borderRadius:9,padding:"9px 18px",fontWeight:700,fontSize:13,cursor:"pointer"}}>✕ Reject</button>
                </div>
              </div>
              <p style={{fontSize:13,color:"var(--text2)",lineHeight:1.6,background:"var(--surface2)",borderRadius:8,padding:"10px 12px"}}>{sub.desc}</p>
            </div>
          ))}
        </div>
      )}

      {/* ADD MANUALLY */}
      {activeSection==="add" && (
        <div style={{background:"var(--surface)",borderRadius:16,padding:"24px 28px",boxShadow:"var(--card-shadow)",border:"1px solid var(--border)"}}>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(240px,1fr))",gap:14}}>
            <div style={{gridColumn:"1/-1"}}><label style={lbl}>Title *</label><input value={form.title} onChange={e=>set("title",e.target.value)} placeholder="Event name" style={inp()} /></div>
            <div><label style={lbl}>Date *</label><input type="date" value={form.date} onChange={e=>set("date",e.target.value)} style={inp()} /></div>
            <div><label style={lbl}>Time</label><input value={form.time} onChange={e=>set("time",e.target.value)} placeholder="e.g. 6:00 PM – 9:00 PM" style={inp()} /></div>
            <div style={{gridColumn:"1/-1"}}><label style={lbl}>Location</label><input value={form.loc} onChange={e=>set("loc",e.target.value)} placeholder="Venue and address" style={inp()} /></div>
            <div><label style={lbl}>Category</label><select value={form.cat} onChange={e=>set("cat",e.target.value)} style={inp()}>{Object.keys(CAT_COLOR).map(c=><option key={c}>{c}</option>)}</select></div>
            <div><label style={lbl}>Recurring?</label><input value={form.recurring} onChange={e=>set("recurring",e.target.value)} placeholder="e.g. Every Friday, Annual" style={inp()} /></div>
            <div style={{gridColumn:"1/-1"}}><label style={lbl}>Description</label><textarea value={form.desc} onChange={e=>set("desc",e.target.value)} placeholder="Describe the event…" style={{...inp(),height:80,resize:"vertical"}} /></div>
            <div style={{gridColumn:"1/-1",borderTop:"2px solid var(--border)",paddingTop:14}}>
              <div style={{fontSize:13,fontWeight:800,color:"var(--navy)",marginBottom:10}}>🔗 Links</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12}}>
                <div><label style={lbl}>🌐 Website / Source URL</label><input value={form.url} onChange={e=>set("url",e.target.value)} placeholder="https://..." style={inp()} /></div>
                <div><label style={lbl}>📘 Facebook Event</label><input value={form.facebook} onChange={e=>set("facebook",e.target.value)} placeholder="https://facebook.com/events/..." style={inp()} /></div>
                <div><label style={lbl}>🎟️ Tickets</label><input value={form.tickets} onChange={e=>set("tickets",e.target.value)} placeholder="https://eventbrite.com/..." style={inp()} /></div>
              </div>
            </div>
            <div style={{gridColumn:"1/-1"}}><label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",fontSize:14,fontWeight:600}}><input type="checkbox" checked={form.featured} onChange={e=>set("featured",e.target.checked)} style={{width:18,height:18}} />⭐ Feature this event</label></div>
          </div>
          <div style={{display:"flex",gap:10,marginTop:18,alignItems:"center"}}>
            <button onClick={saveManual} disabled={!form.title||!form.date} style={{background:(!form.title||!form.date)?"#6b7280":C.red,color:"#fff",border:"none",borderRadius:10,padding:"11px 24px",fontWeight:800,fontSize:15,cursor:(!form.title||!form.date)?"not-allowed":"pointer"}}>Save Event</button>
            <button onClick={()=>setForm(empty)} style={{background:"var(--surface2)",color:"var(--text3)",border:"none",borderRadius:10,padding:"11px 18px",fontWeight:700,fontSize:14,cursor:"pointer"}}>Clear</button>
            {saved && <span style={{color:"var(--navy)",fontWeight:800}}>✅ Saved!</span>}
          </div>
        </div>
      )}

      {/* MANAGE MANUAL EVENTS */}
      {activeSection==="manage" && (
        <div style={{background:"var(--surface)",borderRadius:16,padding:"20px 24px",boxShadow:"var(--card-shadow)",border:"1px solid var(--border)"}}>
          {manualEvents.length===0 ? (
            <div style={{textAlign:"center",padding:"40px",color:"var(--text3)"}}>
              <div style={{fontSize:36}}>📝</div>
              <p style={{marginTop:10,fontWeight:600}}>No manually added events yet.</p>
              <p style={{fontSize:13,marginTop:4}}>Add an event using the "Add Event" section above, or approve a business submission.</p>
            </div>
          ) : (
            <div style={{display:"flex",flexDirection:"column",gap:8}}>
              {manualEvents.sort((a,b)=>(a.date||"").localeCompare(b.date||"")).map(e=>{
                const col=CAT_COLOR[e.cat]||C.navy;
                const {mon,day}=fmtDate(e.date);
                return (
                  <div key={e.id} style={{display:"flex",alignItems:"center",gap:12,padding:"10px 14px",borderRadius:10,border:"1px solid var(--border)",background:e.featured?"#FFF9F0":"#FAFBFF"}}>
                    <div style={{background:col,color:"#fff",borderRadius:8,padding:"4px 8px",textAlign:"center",minWidth:42,flexShrink:0}}>
                      <div style={{fontSize:8,fontWeight:800}}>{mon}</div>
                      <div style={{fontSize:18,fontWeight:900,lineHeight:1}}>{day}</div>
                    </div>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontWeight:700,fontSize:14,color:"var(--text)"}}>{e.title}</div>
                      <div style={{fontSize:11,color:"var(--text3)"}}>{e.cat} · {e.loc}</div>
                      <SourceBadge url={e.url} source={e.source} />
                    </div>
                    <button onClick={()=>toggleFeatured(e.id)} style={{background:e.featured?"#f59e0b":"#E5E7EB",color:e.featured?"#fff":"#6b7280",border:"none",borderRadius:7,padding:"5px 10px",cursor:"pointer",fontSize:12,fontWeight:700}}>⭐</button>
                    <button onClick={()=>removeManual(e.id)} style={{background:"#fee2e2",color:"var(--red)",border:"none",borderRadius:7,padding:"5px 10px",cursor:"pointer",fontSize:12,fontWeight:700}}>✕</button>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}

      {/* LIVE EVENTS PREVIEW */}
      {activeSection==="live" && (
        <div style={{background:"var(--surface)",borderRadius:16,padding:"20px 24px",boxShadow:"var(--card-shadow)",border:"1px solid var(--border)"}}>
          {liveEvents.length===0 ? (
            <div style={{textAlign:"center",padding:"40px",color:"var(--text3)"}}>
              <div style={{fontSize:36}}>🤖</div>
              <p style={{marginTop:10,fontWeight:600}}>No live events loaded yet.</p>
              <p style={{fontSize:13,marginTop:4}}>Go to the Events tab and click "Refresh Live Events" to fetch current events from the web.</p>
            </div>
          ) : (
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {liveEvents.map(e=>{
                const col=CAT_COLOR[e.cat]||C.navy;
                const {mon,day}=fmtDate(e.date);
                return (
                  <div key={e.id} style={{display:"flex",alignItems:"center",gap:12,padding:"9px 12px",borderRadius:10,border:"1px solid var(--border)"}}>
                    <div style={{background:col,color:"#fff",borderRadius:8,padding:"3px 7px",textAlign:"center",minWidth:38,flexShrink:0}}>
                      <div style={{fontSize:7,fontWeight:800}}>{mon}</div>
                      <div style={{fontSize:16,fontWeight:900,lineHeight:1}}>{day}</div>
                    </div>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontWeight:700,fontSize:13,color:"var(--text)"}}>{e.title}</div>
                      <div style={{fontSize:11,color:"var(--text3)"}}>{e.loc}</div>
                    </div>
                    {e.url && <a href={e.url} target="_blank" rel="noreferrer" style={{fontSize:11,color:"var(--navy)",fontWeight:700}}>View →</a>}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ─── DINING TAB ────────────────────────────────────────────────────────────────
const VENUE_TYPE_COLOR = {
  "Italian":              "#7c3aed",
  "Gastropub":            "#b45309",
  "Pizza":                "#dc2626",
  "Pizza & Pub":          "#dc2626",
  "Wood-Fired Pizza":     "#c2410c",
  "Taproom":              "#0369a1",
  "BBQ":                  "#b45309",
  "Bar & Restaurant":     "#0f766e",
  "Bar & Diner":          "#4b5563",
  "Café & Events":        "#7c3aed",
  "Coffee & Café":        "#92400e",
  "Mexican & Tequila Bar":"#15803d",
  "Italian Beef · Carryout":"#9f1239",
  "Craft Brewery":        "#1d4ed8",
  "Wine & Olive Oil":     "#6d28d9",
  "Juice Bar & Wellness": "#16a34a",
};
function DiningTab() {
  const [q, setQ] = useState("");
  const allTypes = [...new Set(RESTAURANTS.map(r => r.type))];
  const [activeType, setActiveType] = useState("All");

  const filtered = RESTAURANTS.filter(r => {
    const matchQ = !q || r.name.toLowerCase().includes(q.toLowerCase()) || r.type.toLowerCase().includes(q.toLowerCase()) || r.promo.toLowerCase().includes(q.toLowerCase());
    const matchT = activeType === "All" || r.type === activeType;
    return matchQ && matchT;
  });

  return (
    <div>
      <div style={{background:`linear-gradient(135deg,${C.navy},#001540)`,borderRadius:18,padding:"28px 32px",marginBottom:24,color:"#fff",position:"relative",overflow:"hidden"}}>
        <div style={{position:"absolute",right:20,top:10,fontSize:90,opacity:0.07}}>🍽️</div>
        <h2 style={{fontSize:26,fontWeight:900,marginBottom:6}}>Prospect Road Dining</h2>
        <p style={{opacity:0.85,fontSize:14,lineHeight:1.65,maxWidth:560}}>Peoria Heights is home to one of central Illinois' finest dining corridors along N. Prospect Road.</p>
      </div>

      {/* Search + type filters */}
      <div className="filter-bar" style={{marginBottom:20}}>
        <input value={q} onChange={e=>setQ(e.target.value)} placeholder="🔍  Search restaurants…" className="filter-input" />
        <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
          {["All",...allTypes].map(t=>{
            const col = VENUE_TYPE_COLOR[t] || C.navy;
            return (
              <button key={t} onClick={()=>setActiveType(t)} className="cat-chip"
                style={{background:activeType===t?col:"var(--surface2)",color:activeType===t?"#fff":"var(--text2)"}}>
                {t}
              </button>
            );
          })}
        </div>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:20}}>
        {filtered.length === 0 ? (
          <div style={{gridColumn:"1/-1",textAlign:"center",padding:"60px 0",color:"var(--text3)"}}>
            <div style={{fontSize:48}}>🍽️</div>
            <p style={{fontSize:18,marginTop:12,fontWeight:600}}>No restaurants found.</p>
          </div>
        ) : filtered.map(r=>{
          const typeCol = VENUE_TYPE_COLOR[r.type] || C.navy;
          return (
          <div key={r.name} className="venue-card">
            <div style={{height:140,background:`linear-gradient(135deg,${typeCol},${typeCol}cc)`,display:"flex",alignItems:"center",justifyContent:"center",position:"relative"}}>
              <span style={{fontSize:60}}>{r.icon}</span>
              <div style={{position:"absolute",top:10,left:10,background:"rgba(0,0,0,0.35)",color:"#fff",borderRadius:7,padding:"3px 10px",fontSize:10,fontWeight:800}}>{r.type}</div>
              <div style={{position:"absolute",bottom:0,left:0,right:0,background:"linear-gradient(transparent,rgba(0,0,0,0.6))",padding:"8px 14px"}}>
                <div style={{color:"#fff",fontSize:13,fontWeight:700}}>{r.name}</div>
              </div>
            </div>
            <div style={{height:4,background:typeCol}} />
            <div style={{padding:"14px 16px",flex:1,display:"flex",flexDirection:"column"}}>
              <div style={{color:"var(--text3)",fontSize:12,lineHeight:1.9,marginBottom:10}}>
                <div>📍 {r.addr}</div>{r.phone&&<div>📞 {r.phone}</div>}<div>🕐 {r.hours}</div>
              </div>
              <div style={{background:"var(--surface2)",border:`1px solid ${typeCol}44`,borderLeft:`3px solid ${typeCol}`,borderRadius:9,padding:"9px 12px",fontSize:12,color:"var(--text2)",fontWeight:600,marginBottom:12,flex:1}}>🎉 {r.promo}</div>
              <div style={{display:"flex",gap:8}}>
                {r.phone&&<a href={`tel:${r.phone}`} style={{flex:1,background:"var(--navy)",color:"#fff",borderRadius:9,padding:"9px 0",fontWeight:700,fontSize:12,textDecoration:"none",textAlign:"center"}}>📞 Call</a>}
                {r.url?<a href={r.url} target="_blank" rel="noreferrer" style={{flex:1,background:typeCol,color:"#fff",borderRadius:9,padding:"9px 0",fontWeight:700,fontSize:12,textDecoration:"none",textAlign:"center"}}>🌐 Website</a>
                :<button style={{flex:1,background:"#E5E7EB",color:"#6b7280",border:"none",borderRadius:9,padding:"9px 0",fontWeight:700,fontSize:12,cursor:"default"}}>🌐 Coming Soon</button>}
              </div>
            </div>
          </div>
        );})}
      </div>
    </div>
  );
}

// ─── EXPLORE TAB ──────────────────────────────────────────────────────────────
function ExploreTab() {
  const places = [
    { name:"Tower Park & Observation Tower", icon:"🗼", type:"Landmark",    hours:"Dawn to Dusk",      addr:"Prospect Road, Peoria Heights", desc:"The iconic 200-ft observation tower with panoramic views of the Illinois River and three counties." },
    { name:"Grand View Drive",               icon:"🌅", type:"Scenic Drive", hours:"Always Open",       addr:"Grand View Drive",              desc:"Named 'World's Most Beautiful Drive' by Teddy Roosevelt in 1910. Breathtaking bluff views of the Illinois River valley." },
    { name:"Forest Park Nature Center",      icon:"🌲", type:"Nature",       hours:"Tue–Sun 9 AM–4 PM", addr:"Forest Park Rd",                desc:"Miles of woodland and restored native prairie trails. Expert-led naturalist programs and seasonal wildflower walks." },
    { name:"Illinois Riverfront",            icon:"🌊", type:"Waterfront",   hours:"Always Open",       addr:"West Peoria Heights",           desc:"Scenic views, boating access, fishing, and stunning sunsets along the majestic Illinois River." },
    { name:"Rock Island Greenway Trail",     icon:"🚴", type:"Trail",        hours:"Dawn to Dusk",      addr:"Rock Island Trail",             desc:"Multi-use trail connecting Peoria Heights to the greater Peoria trail network. Great for cycling and walking." },
    { name:"Lincoln Bronze Sculpture",       icon:"🗿", type:"Landmark",    hours:"Always Open",        addr:"Tower Park",                    desc:"A striking bronze sculpture of Lincoln's head by Gutzon Borglum — the same sculptor who created Mount Rushmore." },
  ];
  const typeCol = { Landmark:C.red, "Scenic Drive":"#002868", Nature:"var(--navy)", Waterfront:"#002868", Trail:"var(--navy)" };
  return (
    <div>
      <div style={{background:"linear-gradient(135deg,#002868,#C8102E)",borderRadius:18,padding:"28px 32px",marginBottom:24,color:"#fff"}}>
        <h2 style={{fontSize:26,fontWeight:900,marginBottom:6}}>Explore Peoria Heights</h2>
        <p style={{opacity:0.85,fontSize:14,lineHeight:1.65}}>From Teddy Roosevelt's "World's Most Beautiful Drive" to Tower Park's panoramic views.</p>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:18,marginBottom:28}}>
        {places.map(p=>{
          const col=typeCol[p.type]||C.navy;
          return (
            <div key={p.name} className="card" style={{background:"var(--surface)",borderRadius:14,overflow:"hidden",border:"1px solid var(--border)",boxShadow:"var(--card-shadow)"}}>
              <div style={{height:150,overflow:"hidden"}}><img src={TOWER} alt={p.name} style={{width:"100%",height:"100%",objectFit:"cover"}} /></div>
              <div style={{height:4,background:col||"var(--navy)"}} />
              <div style={{padding:"14px 18px"}}>
                <span style={{background:col+"18",color:col,borderRadius:20,padding:"2px 9px",fontSize:10,fontWeight:700}}>{p.icon} {p.type}</span>
                <h3 style={{margin:"7px 0 5px",fontSize:15,color:"var(--text)",fontWeight:800}}>{p.name}</h3>
                <p style={{fontSize:13,color:"var(--text2)",lineHeight:1.6,marginBottom:8}}>{p.desc}</p>
                <div style={{fontSize:12,color:"var(--text3)",lineHeight:1.9}}><div>📍 {p.addr}</div><div>🕐 {p.hours}</div></div>
              </div>
            </div>
          );
        })}
      </div>
      <div style={{background:"var(--navy)",borderRadius:18,padding:"26px 30px",color:"#fff",display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(185px,1fr))",gap:22}}>
        {[{icon:"🏛️",t:"Village Hall",l:["4901 N. Prospect Rd","📞 (309) 686-2385","peoriaheights.org"]},{icon:"📅",t:"Board Meetings",l:["1st & 3rd Tuesday monthly","Village Hall · 6:30 PM","Open to all residents"]},{icon:"🚨",t:"Emergency",l:["Police & Fire: 911","Non-Emergency:","(309) 673-4521"]},{icon:"📬",t:"Chamber",l:["peoriaheightschamber.com","info@peoriaheightschamber.com","Submit events via this app!"]}].map(b=>(
          <div key={b.t}><h3 style={{fontSize:15,marginBottom:8,fontWeight:700}}>{b.icon} {b.t}</h3>{b.l.map((l,i)=><div key={i} style={{fontSize:12,opacity:0.75,lineHeight:2}}>{l}</div>)}</div>
        ))}
      </div>
    </div>
  );
}

// ─── LOGO CIRCLE ──────────────────────────────────────────────────────────────
const LOGO_IMG = "data:image/jpeg;base64,";
function Seal({ size = 52 }) {
  return (
    <img
      src={LOGO_IMG}
      alt="Tower Park, Peoria Heights"
      style={{
        width: size,
        height: size,
        borderRadius: "50%",
        objectFit: "cover",
        objectPosition: "center 20%",
        border: "2.5px solid #C8102E",
        flexShrink: 0,
      }}
    />
  );
}

// ─── HEADER (utility + nav + quicklinks, fully responsive) ───────────────────
function Header({ active, onSelect, pendingCount, dark, onToggleDark }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const navItems = [
    ["events",  "📅", "Events"],
    ["dining",  "🍽️", "Dining"],
    ["explore", "🗺️", "Explore"],
    ["submit",  "📣", "Submit Event"],
    ["admin",   "⚙️", "Admin"],
  ];
  function go(id) { onSelect(id); setMenuOpen(false); }

  return (
    <header style={{position:"sticky",top:0,zIndex:100,boxShadow:"0 2px 10px rgba(0,0,0,0.10)"}}>
      {/* Utility bar — hidden on mobile via CSS */}
      <div className="utility-bar">
        <div className="utility-bar-inner">
          <div className="utility-contact">
            <a href="https://peoriaheights.org" target="_blank" rel="noreferrer">peoriaheights.org ↗</a>
          </div>
          <div className="utility-social">
            <a href="https://www.facebook.com/peoriaheightsil" target="_blank" rel="noreferrer">Facebook</a>
            <a href="https://www.instagram.com/peoriaheights" target="_blank" rel="noreferrer">Instagram</a>
          </div>
        </div>
      </div>

      {/* Main nav bar */}
      <div className="main-nav-bar">
        <div className="main-nav-inner">
          <div className="logo-lockup">
            <Seal size={44} />
            <div>
              <div className="logo-title">Heights Live</div>
              <div className="logo-sub">Peoria Heights Community</div>
            </div>
          </div>

          {/* Desktop nav */}
          <nav className="nav-links">
            {navItems.map(([id,ic,lb]) => (
              <button key={id} className={`nav-link${active===id?" active":""}`} onClick={() => go(id)}>
                {ic} {lb}
                {id==="admin" && pendingCount>0 && <span className="badge">{pendingCount}</span>}
              </button>
            ))}
          </nav>

          <button className="dark-toggle" onClick={onToggleDark}>{dark?"☀️":"🌙"}</button>

          {/* Hamburger — shown on mobile via CSS */}
          <button className="hamburger" onClick={() => setMenuOpen(o=>!o)} aria-label="Menu">
            <span style={{transform:menuOpen?"rotate(45deg) translate(5px,5px)":"none",transition:"transform 0.2s"}}/>
            <span style={{opacity:menuOpen?0:1,transition:"opacity 0.2s"}}/>
            <span style={{transform:menuOpen?"rotate(-45deg) translate(5px,-5px)":"none",transition:"transform 0.2s"}}/>
          </button>
        </div>
      </div>

      {/* Mobile drawer */}
      <div className={`mobile-menu${menuOpen?" open":""}`}>
        {navItems.map(([id,ic,lb]) => (
          <button key={id} className={`mobile-nav-link${active===id?" active":""}`} onClick={() => go(id)}>
            <span>{ic}</span>
            <span>{lb}</span>
            {id==="admin" && pendingCount>0 && <span style={{marginLeft:"auto",background:"#C8102E",color:"#fff",borderRadius:10,padding:"1px 6px",fontSize:10,fontWeight:800}}>{pendingCount}</span>}
          </button>
        ))}
      </div>

      {/* Quick-links strip — horizontally scrollable on mobile */}
      <div className="quicklinks-bar">
        <div className="quicklinks-inner">
          <span className="quicklinks-label">I want to:</span>
          {[
            ["📅","See events",     ()=>go("events")],
            ["🍽️","Dining",    ()=>go("dining")],
            ["📣","Submit event",   ()=>go("submit")],
            ["🗺️","Explore",       ()=>go("explore")],
          ].map(([ic,lb,fn])=>(
            <button key={lb} className="quicklink-btn" onClick={fn}>{ic} {lb}</button>
          ))}
        </div>
      </div>
    </header>
  );
}

function Hero({ dark }) {
  const [wx, setWx] = useState(null);
  const [wxError, setWxError] = useState(false);
  useEffect(() => {
    // Calls our secure backend proxy at /api/weather
    fetch("/api/weather")
      .then(r => r.json())
      .then(data => {
        if (data.temp && data.label && data.icon) setWx(data);
        else throw new Error("Bad weather response");
      })
      .catch(() => setWxError(true));
  }, []);

  const today = new Date();
  const dateStr = today.toLocaleDateString("en-US", { weekday:"long", month:"long", day:"numeric" });

  return (
    <div style={{position:"relative",height:"clamp(240px,40vw,340px)",overflow:"hidden",background:"var(--navy)"}}>
      <img src={TOWER} alt="Tower Park at sunset" style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover",objectPosition:"center 30%",opacity:0.45}} />
      <div style={{position:"absolute",inset:0,background:"linear-gradient(105deg, rgba(0,20,80,0.45) 0%, rgba(0,20,80,0.18) 50%, rgba(0,10,40,0.42) 100%)"}} />
      <div style={{position:"absolute",top:0,left:0,right:0,height:5,background:"var(--red)",zIndex:5}} />

      <div style={{position:"relative",zIndex:4,maxWidth:1200,margin:"0 auto",padding:"clamp(20px,4vw,40px) 16px 0",height:"100%",display:"flex",flexDirection:"column",justifyContent:"center"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:16}}>
          <div style={{maxWidth:560,flex:1}}>
            <div className="hero-badge" style={{marginBottom:14}}>
              <Seal size={20} />
              Village Portal
            </div>
            <h1 style={{fontFamily:"'Merriweather',Georgia,serif",color:"#ffffff",fontSize:"clamp(22px,5vw,42px)",fontWeight:900,lineHeight:1.1,letterSpacing:"-0.5px",textShadow:"0 2px 20px rgba(0,0,0,0.5)",marginBottom:10}}>
              Village of<br/>Peoria Heights
            </h1>
            <p style={{color:"rgba(255,255,255,0.88)",fontSize:"clamp(13px,2vw,15px)",lineHeight:1.6,fontWeight:400,textShadow:"0 1px 6px rgba(0,0,0,0.3)",maxWidth:420}}>
              Community events, Prospect Road dining, and local information — always up to date.
            </p>
          </div>

          {/* Weather + date card */}
          <div style={{background:"rgba(255,255,255,0.1)",backdropFilter:"blur(16px)",border:"1px solid rgba(255,255,255,0.2)",borderRadius:12,padding:"16px 20px",color:"#fff",flexShrink:0,minWidth:160}}>
            <div style={{fontSize:9,letterSpacing:"0.15em",textTransform:"uppercase",opacity:0.7,marginBottom:8,fontWeight:700}}>Today · Peoria Heights</div>
            <div style={{fontSize:12,opacity:0.8,marginBottom:10,fontWeight:500}}>{dateStr}</div>
            {wx ? (
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                <span style={{fontSize:28,lineHeight:1}}>{wx.icon}</span>
                <div>
                  <div style={{fontSize:24,fontWeight:900,lineHeight:1}}>{wx.temp}°F</div>
                  <div style={{fontSize:11,opacity:0.7,marginTop:3}}>{wx.label}</div>
                </div>
              </div>
            ) : wxError ? (
              <div style={{fontSize:12,opacity:0.55}}>⚠️ Weather unavailable</div>
            ) : (
              <div style={{display:"flex",alignItems:"center",gap:8,opacity:0.6}}>
                <div style={{width:28,height:28,borderRadius:"50%",border:"3px solid rgba(255,255,255,0.4)",borderTopColor:"#fff",animation:"spin 1s linear infinite"}} />
                <span style={{fontSize:12}}>Loading…</span>
              </div>
            )}
          </div>
        </div>
      </div>

      <div style={{position:"absolute",bottom:10,right:16,color:"rgba(255,255,255,0.35)",fontSize:10,fontStyle:"italic",zIndex:5}}>Tower Park, Peoria Heights</div>
    </div>
  );
}

// ─── MAIN APP ──────────────────────────────────────────────────────────────────
export default function App() {
  const [tab, setTab]                   = useState("events");
  const [dark, setDark]                 = useState(false);
  const [liveEvents, setLiveEvents]     = useState([]);
  const [manualEvents, setManualEvents] = useState([]);
  const [pendingSubs, setPendingSubs]   = useState([]);
  const [liveStatus, setLiveStatus]     = useState("cached");
  const [lastUpdated, setLastUpdated]   = useState(null);

  // Fetch events on mount — server CDN handles 12hr caching
  useEffect(() => {
    setLiveStatus("loading");
    loadStored("manual_events").then(m => setManualEvents(m || []));
    loadStored("pending_subs").then(p => setPendingSubs(p || []));

    fetchLiveEvents()
      .then(events => {
        events.sort((a, b) => (a.date || "").localeCompare(b.date || ""));
        setLiveEvents(events);
        setLastUpdated(Date.now());
        setLiveStatus(events.length > 0 ? "loaded" : "cached");
      })
      .catch(err => {
        console.error("[Events] Fetch failed:", err.message);
        setLiveStatus("error");
      });
  }, []);

  function handleSubmit(sub) {
    const updated = [...pendingSubs, sub];
    setPendingSubs(updated);
    saveStored("pending_subs", updated);
  }

  const allEvents = [...liveEvents, ...manualEvents];

  return (
    <>
      <style>{css}</style>
      <div className={"page-bg"+(dark?" app-dark":"")}>
        <Hero dark={dark} />
        <Header active={tab} onSelect={setTab} pendingCount={pendingSubs.length} dark={dark} onToggleDark={()=>setDark(d=>!d)} />
        <main className="main-content">
          {tab==="events"  && <EventsTab allEvents={allEvents} liveStatus={liveStatus} lastUpdated={lastUpdated} />}
          {tab==="dining"  && <DiningTab />}
          {tab==="explore" && <ExploreTab />}
          {tab==="submit"  && <SubmitTab onSubmit={handleSubmit} />}
          {tab==="admin"   && <AdminTab manualEvents={manualEvents} setManualEvents={setManualEvents} pendingSubs={pendingSubs} setPendingSubs={setPendingSubs} liveEvents={liveEvents} />}
        </main>
        <footer style={{background:"var(--footer-bg)",borderTop:"4px solid var(--red)"}}>
          <div style={{maxWidth:1200,margin:"0 auto",padding:"28px 24px",display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:20}}>
            <div style={{display:"flex",alignItems:"center",gap:14}}>
              <Seal size={44} />
              <div>
                <div style={{fontFamily:"'Merriweather',Georgia,serif",color:"#fff",fontSize:17,fontWeight:900}}>Village of Peoria Heights</div>
                <div style={{color:"rgba(255,255,255,0.5)",fontSize:12,marginTop:3}}>An unofficial community guide to Peoria Heights</div>
              </div>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{color:"rgba(255,255,255,0.4)",fontSize:11,marginBottom:4,letterSpacing:"0.05em"}}>EVENTS SOURCED FROM</div>
              <div style={{color:"rgba(255,255,255,0.6)",fontSize:12}}>Peoria Heights Chamber · Kenny's Pub · Civic Center · Prospect Rd</div>
            </div>
          </div>
        </footer>
      </div>
    </>
  );
}
